parameters.jsCode:
const raw = $input.first().json.text || $input.first().json.output || "";

let cleaned = raw.trim();

// Remove markdown code fences if present
if (cleaned.startsWith("```json")) {
  cleaned = cleaned.replace(/^```json\s*/i, "");
}
if (cleaned.startsWith("```")) {
  cleaned = cleaned.replace(/^```\s*/i, "");
}
if (cleaned.endsWith("```")) {
  cleaned = cleaned.replace(/\s*```$/i, "");
}

// Parse JSON safely
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  return [
    {
      json: {
        error: "Invalid JSON from model",
        rawOutput: raw,
        cleanedOutput: cleaned
      }
    }
  ];
}

return [
  {
    json: parsed
  }
];

const data = $input.first().json;

function esc(text = "") {
  return String(text)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/&/g, '\\&')
    .replace(/%/g, '\\%')
    .replace(/\$/g, '\\$')
    .replace(/#/g, '\\#')
    .replace(/_/g, '\\_')
    .replace(/{/g, '\\{')
    .replace(/}/g, '\\}')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}')
    .replace(/[–—]/g, '--')
    .replace(/[’]/g, "'")
    .replace(/[“”]/g, '"');
}

const name = esc(data.name || "ANISH KRISHNAKANT AYARE");
const phone = esc(data.phone || "(551) 260-8994");
const email = esc(data.email || "anishayare421@gmail.com");
const location = esc(data.location || "USA");
const linkedin = data.linkedin || "https://www.linkedin.com/in/anishayare";
const github = data.github || "https://github.com/Anish010402";

const summary = esc(data.summary || "");
const skills = data.skills || {};

const experience = (data.experience || []).map(job => {
  const bullets = (job.bullets || [])
    .map(b => `\\item ${esc(b)}`)
    .join('\n');

  return `
\\textbf{${esc(job.title)} \\hfill ${esc(job.company)}${job.location ? `, ${esc(job.location)}` : ""}} \\\\
\\textit{${esc(job.dates)}}
\\begin{itemize}[leftmargin=*, itemsep=1pt, parsep=0pt, partopsep=0pt, topsep=-7pt]
${bullets}
\\end{itemize}

\\vspace{5pt}
`;
}).join('\n');

const education = (data.education || []).map(ed => {
  return `\\textbf{${esc(ed.degree)} \\hfill ${esc(ed.school)}${ed.location ? `, ${esc(ed.location)}` : ""}} \\\\
${esc(ed.dates)} \\\\`;
}).join('\n');

const latex = `
\\documentclass[10pt]{article}

\\usepackage[margin=0.35in]{geometry}
\\usepackage[hidelinks]{hyperref}
\\usepackage{enumitem}
\\usepackage{titlesec}
\\usepackage{times}
\\usepackage{microtype}

\\pagestyle{empty}
\\setlength{\\parindent}{0pt}

\\linespread{0.98}

\\setlist[itemize]{leftmargin=*, itemsep=0pt, parsep=0pt, partopsep=0pt, topsep=0pt}
\\titlespacing{\\section}{0pt}{0pt}{3pt}
\\titleformat{\\section}{\\bfseries}{}{0em}{}[\\titlerule]

\\begin{document}

\\begin{center}
{\\large \\textbf{${name}}} \\\\
{\\small ${phone} \\;|\\; ${email} \\;|\\; ${location} \\;|\\;
\\href{${linkedin}}{LinkedIn} \\;|\\;
\\href{${github}}{GitHub}}
\\end{center}

\\vspace{5pt}

\\section*{SUMMARY}
${summary}

\\vspace{5pt}

\\section*{SKILLS}

\\textbf{Programming Languages:} ${esc(skills.programmingLanguages || "")} \\\\
\\textbf{Frontend Technologies:} ${esc(skills.frontendTechnologies || "")} \\\\
\\textbf{Backend \\& API Development:} ${esc(skills.backendApiDevelopment || "")} \\\\
\\textbf{Databases \\& Data Management:} ${esc(skills.databasesDataManagement || "")} \\\\
\\textbf{Cloud \\& DevOps:} ${esc(skills.cloudDevOps || "")} \\\\
\\textbf{Testing \\& Quality Engineering:} ${esc(skills.testingQualityEngineering || "")} \\\\
\\textbf{AI \\& Advanced Analytics:} ${esc(skills.aiAdvancedAnalytics || "")} \\\\
\\textbf{Security \\& Compliance:} ${esc(skills.securityCompliance || "")} \\\\
\\textbf{Development Practices \\& Tools:} ${esc(skills.developmentPracticesTools || "")}

\\vspace{5pt}

\\section*{EXPERIENCE}

${experience}

\\vspace{5pt}

\\section*{EDUCATION}
${education}

\\end{document}
`.trim();

return [
  {
    json: {
      latex
    }
  }
];

